(423, '_transient_woocommerce_admin_pes_incentive_woopayments_cache', 'a:3:{s:10:\"incentives\";a:2:{i:0;a:8:{s:2:\"id\";s:32:\"wcpay-promo-2023-action-discount\";s:8:\"promo_id\";s:32:\"wcpay-promo-2023-action-discount\";s:4:\"type\";s:12:\"welcome_page\";s:9:\"cta_label\";s:35:\"Cài đặt WooPayments miễn phí\";s:6:\"tc_url\";s:75:\"https://woocommerce.com/terms-conditions/woopayments-action-promotion-2023/\";s:11:\"description\";s:142:\"<b>Lưu 10%</b> trên chi phí xử lý thanh toán trong <b>ba tháng đầu tiên</b> của bạn khi bạn Đăng ký WooPayments hôm nay.\";s:19:\"task_header_content\";s:365:\"Cung cấp sức mạnh cho các khoản thanh toán của bạn với một tuỳ chọn đơn giản, tất cả trong một và <b>lưu 10% vào chi phí xử lý thanh toán trong ba tháng đầu tiên</b>. Xem <a href=\"https://woocommerce.com/terms-conditions/woopayments-action-promotion-2023/\">Điều Khoản và Điều Kiện</a> để biết chi tiết.\";s:10:\"task_badge\";s:40:\"Lưu 10% trên phí xử lý thanh toán\";}i:1;a:9:{s:2:\"id\";s:54:\"wcpay-promo-2023-action-discount__wc_settings_payments\";s:8:\"promo_id\";s:32:\"wcpay-promo-2023-action-discount\";s:4:\"type\";s:20:\"wc_settings_payments\";s:11:\"description\";s:249:\"Sử dụng giải pháp thanh toán nội địa được xây dựng và Hỗ trợ bởi Woo để chấp nhận thanh toán trực tuyến và trực tiếp, theo dõi doanh thu, và xử lý tất cả hoạt động thanh toán ở một nơi.\";s:9:\"cta_label\";s:17:\"Cài và lưu 10%\";s:6:\"tc_url\";s:75:\"https://woocommerce.com/terms-conditions/woopayments-action-promotion-2023/\";s:5:\"title\";s:89:\"Lưu 10% vào phí xử lý trong 3 tháng đầu tiên khi bạn Đăng ký WooPayments.\";s:17:\"short_description\";s:89:\"Lưu 10% vào phí xử lý trong 3 tháng đầu tiên khi bạn Đăng ký WooPayments.\";s:5:\"badge\";s:27:\"Lưu 10% vào phí xử lý\";}}s:12:\"context_hash\";s:32:\"a868ef2cfffc8a74f473cc1d0280f25c\";s:9:\"timestamp\";i:1773128851;}', 'off'),
